+ static int
+ write_FAT(int fd, struct fd_type *fdt) {
+ 
+ 	int i, Media, SecPerClust, RootDirBlks, FATsecs;
+ 	struct bootsector33 bs33;
+ 	struct byte_bpb33  *b33;
+ 
+ 
+ 	b33 = (struct byte_bpb33 *) bs33.bsBPB;
+ 
+ 	if (sizeof(bs33) != 512) {
+ 		fprintf(stderr,"Check definition of struct bootsector33!\n");
+ 		fprintf(stderr,"Sizof (struct bootsector33) != 512.\n");
+ 		exit (3);
+ 	}
+ 
+ 
+ 	/* The following code is heavily borrowed from msdosfs
+ 	 * and mformat from mtools.
+ 	 *
+ 	 * I have no documentation about the FAT. So I just rely
+ 	 * on those two sources :-))
+ 	 *
+ 	 * This function returns the number of written boot, FAT
+ 	 * and root-dir blocks.
+ 	 */
+ 
+ 	switch(fdt->size/2) {		/* size in KBytes */
+ 		int FatGuess, NumClus;
+ 	case 160:
+ 		Media = 0xfe;
+ 		SecPerClust = 1;
+ 		RootDirBlks = 4;
+ 		FATsecs = 1;
+ 		break;
+ 	case 180:
+ 		Media = 0xfc;
+ 		SecPerClust = 1;
+ 		RootDirBlks = 4;
+ 		FATsecs = 2;
+ 		break;
+ 	case 320:
+ 		Media = 0xff;
+ 		SecPerClust = 2;
+ 		RootDirBlks = 7;
+ 		FATsecs = 1;
+ 		break;
+ 	case 360:
+ 		Media = 0xfd;
+ 		SecPerClust = 2;
+ 		RootDirBlks = 7;
+ 		FATsecs = 2;
+ 		break;
+ 	case 720:
+ 		Media = 0xf9;
+ 		SecPerClust = 2;
+ 		RootDirBlks = 7;
+ 		FATsecs = 3;
+ 		break;
+ 	case 1200:
+ 		Media = 0xf9;
+ 		SecPerClust = 1;
+ 		RootDirBlks = 14;
+ 		FATsecs = 7;
+ 		break;
+ 	case 1440:
+ 		Media = 0xf0;
+ 		SecPerClust = 1;
+ 		RootDirBlks = 14;
+ 		FATsecs = 9;
+ 		break;
+ 	case 800:
+ 	case 820:
+ 	case 1480:
+ 	default:		/* non standard format */
+ 		Media = 0xf0;
+ 		if (fdt->heads == 1) {
+ 			SecPerClust = 1;
+ 			RootDirBlks = 4;
+ 		}else {
+ 			if (fdt->size > 2000) {
+ 				SecPerClust = 1;
+ 				RootDirBlks = 14;
+ 			} else {
+ 				SecPerClust = 2;
+ 				RootDirBlks = 7;
+ 			}
+ 		}
+ 		/* fat length. 341 is the number of 12 bit fat entries
+ 		 * per sector */
+ 		FatGuess = ((fdt->size / SecPerClust) / 341.0) + 0.95;
+ 		NumClus = (fdt->size - RootDirBlks - 2 * FatGuess - 1)
+ 			/ SecPerClust;
+ 		FATsecs = (NumClus / 341.) + 1;
+ 		break;
+ 	}
+ 
+ 	/* Set up the boot sector */
+ 
+ 	bs33.bsJump[0] = 0xeb;
+ 	bs33.bsJump[1] = 0x44;
+ 	bs33.bsJump[2] = 0x90;
+ 	strncpy(bs33.bsOemName,"4.4BSD  ",8);
+ 
+ 	putushort(b33->bpbBytesPerSec, 512);
+ 	b33->bpbSecPerClust = SecPerClust;
+ 	putushort(b33->bpbResSectors,1);
+ 	b33->bpbFATs = 2;
+ 	putushort(b33->bpbRootDirEnts, RootDirBlks * 16);
+ 	putushort(b33->bpbSectors, fdt->size);
+ 	b33->bpbMedia = Media;
+ 	putushort(b33->bpbFATsecs, FATsecs);
+ 	putushort(b33->bpbSecPerTrack, fdt->sectrac);
+ 	putushort(b33->bpbHeads, fdt->heads);
+ 	putushort(b33->bpbHiddenSecs, 0);
+ 
+ 	bs33.bsDriveNumber = 0x00;
+ 	/* clear the bootcode */
+ 	memset(bs33.bsBootCode, 0, sizeof bs33.bsBootCode);
+ 	bs33.bsBootSectSig = BOOTSIG;
+ 
+ 
+ #ifdef TEST_DOS_FAT
+ 	printf("jmp: %02x%02x%02x\n",bs33.bsJump[0], 
+ 		bs33.bsJump[1], bs33.bsJump[2]);
+ 	printf("OEM: %s\n",bs33.bsOemName);
+ 	printf("Drv: %04x\n", bs33.bsDriveNumber);
+ 	printf("Sig: %04x\n", bs33.bsBootSectSig);
+ 
+ 	printf("Bytes/sector     = %4d\n", getushort(b33->bpbBytesPerSec));
+ 	printf("Sectors/cluster  = %4d\n", b33->bpbSecPerClust);
+ 	printf("Reserved sectors = %4d\n", getushort(b33->bpbResSectors));
+ 	printf("Sectors/track    = %4d\n", getushort(b33->bpbSecPerTrack));
+ 	printf("Number of FATs   = %4d\n", b33->bpbFATs);
+ 	printf("Root dir entries = %4d\n", getushort(b33->bpbRootDirEnts));
+ 	printf("Total # of secs  = %4d\n", getushort(b33->bpbSectors));
+ 	printf("Media descriptor = %4d %c\n", b33->bpbMedia, b33->bpbMedia);
+ 	printf("Sectors/FAT      = %4d\n", getushort(b33->bpbFATsecs));
+ 	printf("Number of heads  = %4d\n", getushort(b33->bpbHeads));
+ 	printf("Hidden sectors   = %4d\n", getushort(b33->bpbHiddenSecs));
+ #endif
+ 
+ 	/* write bootsector to disk */
+ 	lseek(fd, (off_t) 0, SEEK_SET);
+ 	if (512 != write(fd, &bs33, 512) ) {
+ 		perror("Error writing DOS-block0.\n");
+ 		exit (3);
+ 	}
+ 
+ 
+ 	/*
+ 	 * now we use bs33 for FAT and root directory
+ 	 */
+ 	memset(&bs33, 0, (size_t) 512);
+ 
+ 	/* first FAT first block */
+ 	bs33.bsJump[0] = Media;
+ 	bs33.bsJump[1] = 0xff;
+ 	bs33.bsJump[2] = 0xff;
+ 	if (512 != write(fd, &bs33, 512) ) {
+ 		perror("Error writing FAT.\n");
+ 		exit (3);
+ 	}
+ 
+ 	/* first FAT remaining blocks */
+ 	bs33.bsJump[0] = 0x00;
+ 	bs33.bsJump[1] = 0x00;
+ 	bs33.bsJump[2] = 0x00;
+ 	for (i = 1; i < FATsecs; i++)
+ 		if (512 != write(fd, &bs33, 512) ) {
+ 			perror("Error writing FAT.\n");
+ 			exit (3);
+ 		}
+ 
+ 	/* second FAT first block */
+ 	bs33.bsJump[0] = Media;
+ 	bs33.bsJump[1] = 0xff;
+ 	bs33.bsJump[2] = 0xff;
+ 	if (512 != write(fd, &bs33, 512) ) {
+ 		perror("Error writing FAT.\n");
+ 		exit (3);
+ 	}
+ 
+ 	/* second FAT remaining blocks */
+ 	bs33.bsJump[0] = 0x00;
+ 	bs33.bsJump[1] = 0x00;
+ 	bs33.bsJump[2] = 0x00;
+ 	for (i = 1; i < FATsecs; i++)
+ 		if (512 != write(fd, &bs33, 512) ) {
+ 			perror("Error writing FAT.\n");
+ 			exit (3);
+ 		}
+ 
+ 	/* the root directory */
+ 	for (i = 0; i < RootDirBlks; i++)
+ 		if (512 != write(fd, &bs33, 512) ) {
+ 			perror("Error writing FAT.\n");
+ 			exit (3);
+ 		}
+ 
+ 	return (1 + 2 * FATsecs + RootDirBlks);
+ }
+ 
